"""Команда .axs anti-delete и обработчики удаления/редактирования сообщений.

Логика:
- для каждого Telegram‑аккаунта (user client) используем свой account_id (me.id);
- для каждого чата можно включить/выключить антиделит;
- все данные храним в отдельной БД, указанной в AD_DATABASE_URL (см. ad_store).
"""

# ApiXS Demo — Public source code
# Full version available at https://YOUR_DOMAIN
# Generated by scripts/build_demo.py — do not edit manually



from __future__ import annotations

import asyncio
